# run in kubernetes
kubectl apply -f - <<EOF
apiVersion: apiextensions.k8s.io/v1
kind: CustomResourceDefinition
metadata: {name: testcr.crd.com}
spec:
  group: crd.com
  scope: Namespaced
  names: {plural: testcr, singular: testcr, kind: Testcr}
  versions:
  - name: v1
    served: true
    storage: true
    schema: {openAPIV3Schema: {type: object, properties: {spec: {type: object}}}}
  - name: v2
    served: true
    storage: false
    schema: {openAPIV3Schema: {type: object, properties: {spec: {type: object}}}}
  conversion:
    strategy: Webhook
    webhook:
      clientConfig:
        url: https://8.8.8.8
        caBundle: 
      conversionReviewVersions: ["v1"]
EOF

kubectl apply -f - <<EOF
apiVersion: crd.com/v1
kind: Testcr
metadata:
  name: test-cr
  namespace: default
spec:
EOF

kubectl create sa crdtest
kubectl create clusterrole crd-patch --verb=patch --resource=customresourcedefinitions
kubectl create clusterrolebinding crdtest --clusterrole=crd-patch --serviceaccount=default:crdtest